<!DOCTYPE html><html><head><title>{{ $title }}</title><style>body{font-family:Arial;margin:24px;font-size:10px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #cbd5e1;padding:5px}th{background:#f1f5f9}.header{text-align:center;border-bottom:2px solid #111827;padding-bottom:8px;margin-bottom:10px}.title{font-size:16px;font-weight:bold}</style></head><body><div class="header"><div class="title">{{ $company?->name ?? config('app.name') }}</div><div>{{ $company?->address ?? '' }}</div><h2>{{ strtoupper($title) }}</h2></div><table><thead><tr><th>Date</th><th>Account</th><th>Reference</th><th>Narration</th><th style="text-align:right">Debit</th><th style="text-align:right">Credit</th></tr></thead><tbody>@foreach($entries as $entry)<tr><td>{{ $entry->entry_date?->format('d M Y') ?? $entry->transaction_date?->format('d M Y') }}</td><td>{{ $entry->account_name ?? $entry->account }}</td><td>{{ $entry->reference }}</td><td>{{ $entry->description ?? $entry->narration }}</td><td style="text-align:right">{{ number_format((float)($entry->debit ?? $entry->debit_amount ?? 0),2) }}</td><td style="text-align:right">{{ number_format((float)($entry->credit ?? $entry->credit_amount ?? 0),2) }}</td></tr>@endforeach</tbody></table><script>window.onload=function(){window.print()}</script></body></html>